// Basic GET request
async function getUser(id) {
  const res = await fetch(`/api/users/${id}`);

  // fetch does NOT throw on 4xx/5xx — must check manually!
  if (!res.ok) {
    throw new Error(`HTTP error: ${res.status}`);
  }

  const data = await res.json(); // parse JSON body
  return data;
}

