// ES6 Class with private fields and static methods
class BankAccount {
  #balance = 0;          // private field — inaccessible outside
  #owner;

  constructor(owner, initialDeposit = 0) {
    this.#owner = owner;
    this.#balance = initialDeposit;
  }

  deposit(amount) {
    if (amount <= 0) throw new Error('Amount must be positive');
    this.#balance += amount;
    return this;
  }

  get balance() { return this.#balance; }  // public getter

  static createSavings(owner) {
    return new BankAccount(owner, 100); // factory static method
  }
}

