// Basic generator: pauses at each yield
function* counter(start = 0) {
  while (true) {
    yield start++; // pauses here, resumes on next next() call
  }
}

const gen = counter(1);
console.log(gen.next()); // { value: 1, done: false }
console.log(gen.next()); // { value: 2, done: false }
console.log(gen.next()); // { value: 3, done: false }
// Infinite sequence — no memory issue because values are lazy

// Finite generator — 'done' becomes true after last yield
function* range(start, end, step = 1) {
  for (let i = start; i < end; i += step) {
    yield i;
  }
}

// Use with for...of (calls next() internally)
for (const num of range(0, 10, 2)) {
  console.log(num); // 0, 2, 4, 6, 8
}

// Spread and destructuring work with generators (they are iterables)
const first5 = [...range(1, 6)]; // [1, 2, 3, 4, 5]

// Async generator: for paginated API results
async function* fetchPages(url) {
  let page = 1;
  while (true) {
    const res = await fetch(`${url}?page=${page}`);
    const data = await res.json();
    if (!data.items.length) return; // stop when no more data
    yield data.items;
    page++;
  }
}

// Consume async generator with for await...of
