// Custom Error classes
class ValidationError extends Error {
  constructor(field, message) {
    super(message);
    this.name = 'ValidationError'; // override default 'Error'
    this.field = field;            // custom property
  }
}

class NetworkError extends Error {
  constructor(statusCode, message) {
    super(message);
    this.name = 'NetworkError';
    this.statusCode = statusCode;
  }
}

// Classify errors by type
function handleError(err) {
  if (err instanceof ValidationError) {
    console.log(`Validation failed on field '${err.field}': ${err.message}`);
  } else if (err instanceof NetworkError) {
    console.log(`Network error ${err.statusCode}: ${err.message}`);
  } else {
    throw err; // re-throw unknown errors
  }
}

// Async error handling
async function fetchData(url) {
  try {
    const res = await fetch(url);
    if (!res.ok) throw new NetworkError(res.status, 'Request failed');
    return await res.json();
  } catch (err) {
    handleError(err);
  }
}

